#include <stdio.h>

int main() {
    char op;
    double n1, n2;
    int running = 1;

    printf("Example: Simple Calculator\n");

    while (running) {
        printf("Enter operator (+, -, *, /) or 'q' to quit: ");
        scanf(" %c", &op); // Space before %c skips whitespace

        if (op == 'q') {
            printf("Exiting... Bye!\n");
            break; // Break needs to be inside a loop or switch
        }

        printf("Enter two numbers: ");
        scanf("%lf %lf", &n1, &n2);

        switch (op) {
            case '+':
                printf("Result: %.2lf\n", n1 + n2);
                break;
            case '-':
                printf("Result: %.2lf\n", n1 - n2);
                break;
            case '*':
                printf("Result: %.2lf\n", n1 * n2);
                break;
            case '/':
                if (n2 != 0)
                    printf("Result: %.2lf\n", n1 / n2);
                else
                    printf("Error: Division by zero!\n");
                break;
            default:
                printf("Error: Invalid operator\n");
        }
        printf("--------------------\n");
    }
    return 0;
}
